import { createApiCall, HttpMethod } from "./api";
import { BusinessEndPoints } from "@/constants/ApiConstants";
import { CreateBusinessPayload, UpdateBusinessPayload } from "@/types/business.types";
import { PaginationRequest } from "@/types/api.types";

const generic = (status: number, fallback: string): string => {
    switch (status) {
        case 0: return 'Network error. Please check your internet connection.';
        case 400: return 'Invalid business data. Please check all fields.';
        case 401: return 'Unauthorized. Please login again.';
        case 403: return 'Access denied. You do not have permission for this action.';
        case 404: return 'Business not found.';
        case 409: return 'Business already exists.';
        case 429: return 'Too many requests. Please wait a moment.';
        case 500: return 'Server error. Please try again later.';
        default: return fallback;
    }
};

export const BusinessServicesError = {
    GetBusinessesError:   (s: number) => generic(s, 'Failed to load businesses. Please try again.'),
    SearchBusinessError:  (s: number) => generic(s, 'Failed to search businesses. Please try again.'),
    CreateBusinessError:  (s: number) => generic(s, 'Failed to create business. Please try again.'),
    UpdateBusinessError:  (s: number) => generic(s, 'Failed to update business. Please try again.'),
};

export const BusinessServices = {
    // Public: list all businesses (paged, optional category filter). Reserved for future directory page.
    GetBusinesses:        async (paginationRequest?: PaginationRequest, category?: string) =>
        createApiCall(HttpMethod.GET, BusinessEndPoints.GetBusinesses(paginationRequest, category)),
    // Authenticated: Fetch businesses owned by the current user.
    GetMyBusinessList:    async (paginationRequest?: PaginationRequest) =>
        createApiCall(HttpMethod.GET, BusinessEndPoints.GetMyBusinesses(paginationRequest)),
    // Public: Fetch a single business by id (for edit form pre-population).
    GetBusinessById:      async (id: string) =>
        createApiCall(HttpMethod.GET, BusinessEndPoints.GetBusinessById(id)),
    // Authenticated: Create a new business listing for the current user.
    CreateBusiness:       async (payload: CreateBusinessPayload) =>
        createApiCall(HttpMethod.POST, BusinessEndPoints.PostBusiness(), payload),
    // Authenticated: Update an existing business listing.
    UpdateBusiness:       async (payload: UpdateBusinessPayload) =>
        createApiCall(HttpMethod.PATCH, BusinessEndPoints.PatchBusiness(payload.id), payload),
    // Authenticated: Delete a business listing.
    DeleteBusiness:       async (id: string) =>
        createApiCall(HttpMethod.DELETE, BusinessEndPoints.DeleteBusiness(id)),
};
