import { EventResult } from '@/types/event.types';
import { storage } from './storage';
import { logger } from './logger';

const SELECTED_EVENT_KEY = 'selectedEventContext';

/**
 * Initialize the event context with the default event ID from environment
 * This is used for migration from env variable to localStorage
 */
export const initializeEventContext = (defaultEventId?: string): void => {
    if (!hasSelectedEventContext() && defaultEventId) {
        // Create a basic event object with just the ID for backwards compatibility
        const now = new Date().getTime(); // Get current timestamp as number
        const defaultEvent: EventResult = {
            id: defaultEventId,
            title: `Event ${defaultEventId}`,
            details: 'Migrated from environment variable',
            startDateTime: now,
            endDateTime: now,
            contact: 'Admin',
            location: '',
            registrationLink: '',
            locationLink: '',
            isOnlineMeeting: false,
            isRegistrationEnabled: false,
            isCheckinEnabled: true,
            food: '',
            isFoodEnabled: false,
            isAccompanyEnabled: false,
            owners: [],
            managers: [],
            createdAt: now,
            modifiedAt: now,
            createdBy: 'system',
            createdByName: 'System Migration',
            modifiedBy: 'system'
        };
        saveSelectedEventContext(defaultEvent);
    }
};

/**
 * Get the selected event context from localStorage
 * @returns EventResult or null if no event is selected
 */
export const getSelectedEventContext = (): EventResult | null => {
    try {
        return storage.get<EventResult | null>(SELECTED_EVENT_KEY, null);
    } catch (error) {
        logger.error('eventContext', 'Failed to load selected event from localStorage', error);
        return null;
    }
};

/**
 * Get the selected event ID from localStorage
 * @returns string or null if no event is selected
 */
export const getSelectedEventId = (): string | null => {
    const event = getSelectedEventContext();
    return event?.id || null;
};

/**
 * Save the selected event context to localStorage
 * @param event - The event to save
 */
export const saveSelectedEventContext = (event: EventResult): void => {
    try {
        storage.set(SELECTED_EVENT_KEY, event);
    } catch (error) {
        logger.error('eventContext', 'Failed to save selected event to localStorage', error);
    }
};

/**
 * Clear the selected event context from localStorage
 */
export const clearSelectedEventContext = (): void => {
    try {
        storage.remove(SELECTED_EVENT_KEY);
    } catch (error) {
        logger.error('eventContext', 'Failed to clear selected event from localStorage', error);
    }
};

/**
 * Check if an event context is currently selected
 * @returns boolean
 */
export const hasSelectedEventContext = (): boolean => {
    return getSelectedEventContext() !== null;
};