import { createApiCall, HttpMethod } from "./api";
import { AttendeeEndPoints } from "@/constants/ApiConstants";
import { PaginationRequest } from "@/types/api.types";
import { CheckInPayload, RegisterPayload, UpdateAttendeePayload } from "@/types/attendee.types";

const generic = (status: number, fallback: string): string => {
    switch (status) {
        case 0: return 'Network error. Please check your internet connection.';
        case 400: return 'Invalid request data.';
        case 401: return 'Unauthorized. Please login again.';
        case 403: return 'Access denied. You do not have permission for this action.';
        case 404: return 'Not found.';
        case 409: return 'Already registered or registration not enabled.';
        case 429: return 'Too many requests. Please wait a moment.';
        case 500: return 'Server error. Please try again later.';
        default: return fallback;
    }
};

export const AttendeeServicesError = {
    RegisterAttendeeError: (s: number) => generic(s, 'Registration failed. Please try again.'),
    CancelRegistrationError: (s: number) => generic(s, 'Failed to cancel registration. Please try again.'),
    DeleteRegistrationError: (s: number) => generic(s, 'Failed to delete attendee. Please try again.'),
    CheckInError: (s: number) => generic(s, 'Check-in failed. Please try again.'),
    GetAttendeeByPhoneError: (s: number) => generic(s, 'Failed to search attendees. Please try again.'),
    GetAttendeeError: (s: number) => generic(s, 'Failed to fetch attendee. Please try again.'),
    UpdateRegistrationError: (s: number) => generic(s, 'Failed to update registration. Please try again.'),
};

export const AttendeeServices = {
    // Authenticated: Fetch all attendees for an event (paged). Used by the admin attendee list.
    GetAttendees: async (eventId: string, paginationRequest?: PaginationRequest) =>
        createApiCall(HttpMethod.GET, AttendeeEndPoints.GetAttendees(eventId, paginationRequest)),
    // EventMgr/Admin: Fetch a single attendee by userId. Used to check registration status on event cards.
    GetAttendeeById: async (eventId: string, userId: string) =>
        createApiCall(HttpMethod.GET, AttendeeEndPoints.GetAttendeeById(eventId, userId)),
    // EventMgr/Admin: Search attendees by phone number. Used by check-in search.
    GetAttendeeByPhone: async (eventId: string, phone: string) =>
        createApiCall(HttpMethod.GET, AttendeeEndPoints.GetAttendeeByPhone(eventId, phone)),
    // Authenticated: List events the current user is registered for. Reserved for a future "My Events" page.
    GetMyEvents: async (paginationRequest?: PaginationRequest) =>
        createApiCall(HttpMethod.GET, AttendeeEndPoints.GetMyEvents(paginationRequest)),
    // Authenticated: Self-register the current user for an event. Called from the event card "Register" button.
    RegisterAttendee: async (eventId: string, foodPreference: string, headCount: number = 1) =>
        createApiCall<RegisterPayload>(HttpMethod.POST, AttendeeEndPoints.PostMyRegistration(eventId), { foodPreference, headCount }),
    // Admin/EventMgr: register another user for an event by userId.
    RegisterAttendeeById: async (eventId: string, userId: string, foodPreference: string, headCount: number = 1) =>
        createApiCall<RegisterPayload>(HttpMethod.POST, AttendeeEndPoints.PostRegistrationById(eventId, userId), { foodPreference, headCount }),
    // Authenticated: Self-update food preference / headcount. Also used to soft-cancel (headCount=0).
    UpdateRegistration: async (eventId: string, foodPreference: string, headCount: number = 1) =>
        createApiCall<UpdateAttendeePayload>(HttpMethod.PATCH, AttendeeEndPoints.PatchMyRegistration(eventId), { foodPreference, headCount }),
    // Admin/EventMgr: update another user's food preference / headcount.
    UpdateRegistrationById: async (eventId: string, userId: string, foodPreference: string, headCount: number = 1) =>
        createApiCall<UpdateAttendeePayload>(HttpMethod.PATCH, AttendeeEndPoints.PatchRegistrationById(eventId, userId), { foodPreference, headCount }),
    // Admin/EventMgr: append a donation entry (format: "amount@txnRef") to an attendee's record.
    AddDonation: async (eventId: string, userId: string, donation: string) =>
        createApiCall<UpdateAttendeePayload>(HttpMethod.PATCH, AttendeeEndPoints.PatchRegistrationById(eventId, userId), { donation }),
    // Admin/EventMgr: toggle check-in status for an attendee.
    CheckInAttendee: async (eventId: string, userId: string, isCheckedIn: boolean) =>
        createApiCall<CheckInPayload>(HttpMethod.PATCH, AttendeeEndPoints.PatchCheckIn(eventId, userId), { isCheckedIn }),
    // Admin/EventMgr: permanently delete an attendee's registration record.
    DeleteRegistrationById: async (eventId: string, userId: string) =>
        createApiCall(HttpMethod.DELETE, AttendeeEndPoints.DeleteRegistrationById(eventId, userId)),
};
