import axios, { AxiosInstance, AxiosResponse } from 'axios'
import { AxiosConfig } from '../constants/ApiConstants'
import { GetAccessToken, ClearAccessTokenData } from '../utils/token'
import { logger } from '../utils/logger'

const AxiosAuthInstance: AxiosInstance = axios.create({
    headers: {
        'Content-Type': 'application/json'
    }
})

const exponentialDelay = (retryLeft: number): number => {
    const retryingFor = AxiosConfig.retry - retryLeft
    return AxiosConfig.firstRetryAt * 2 ** retryingFor
}

// Legacy envelope returned by the API: { status, errorCode, result, error }.
// The correlation id is delivered via the X-Correlation-Id response header (not in the body).
type LegacyResponse<T> = { status: number; errorCode: number; result?: T; error?: string };

// API now always returns the legacy envelope. This wraps any non-conforming response
// (e.g. a stray raw body or unhandled error page) so consumers stay safe.
const adaptResponseBody = (body: unknown, httpStatus: number): LegacyResponse<unknown> => {
    if (body && typeof body === 'object' && 'status' in body && 'errorCode' in body) {
        return body as LegacyResponse<unknown>;
    }
    return {
        status: httpStatus,
        errorCode: httpStatus >= 200 && httpStatus < 300 ? 0 : httpStatus,
        result: body,
    };
};

AxiosAuthInstance.interceptors.request.use(
    async (axiosConfig) => {
        try {
            const bearerToken = GetAccessToken();
            if (bearerToken) {
                axiosConfig.headers['Authorization'] = `Bearer ${bearerToken}`;
            }
            return axiosConfig;
        } catch (error) {
            return Promise.reject(error);
        }
    }
);

AxiosAuthInstance.interceptors.response.use(
    (response: AxiosResponse) => {
        response.data = adaptResponseBody(response.data, response.status);
        return response;
    },
    async (error) => {
        const status = error?.response?.status;
        const config = error?.config;

        if (error?.response) {
            error.response.data = adaptResponseBody(error.response.data, status);
        }

        // 401 → clear token and redirect to expired. 403 is a permission error, do not redirect.
        // Exception: 401 from auth endpoints themselves (e.g. wrong OTP at /auth/token) is just a
        // failed login attempt — keep the user on the login page and surface the error inline.
        if (status === 401) {
            const url: string = config?.url ?? '';
            const isAuthEndpoint = url.includes('/auth/token') || url.includes('/auth/otp');
            if (!isAuthEndpoint) {
                ClearAccessTokenData();
                window.location.href = '/expired';
            }
            return Promise.reject(error);
        }

        if (status === 403) {
            logger.error('axios-auth', 'Access forbidden: You do not have permission to perform this action.', null);
            return Promise.reject(error);
        }

        if (!config?.retry || status < 500) {
            return Promise.reject(error);
        }
        config.retry -= 1
        await new Promise<void>((resolve) => {
            setTimeout(() => {
                resolve();
            }, exponentialDelay(config.retry));
        });
        return AxiosAuthInstance(config);
    }
)

export default AxiosAuthInstance
