import { createApiCall, HttpMethod } from "./api";
import { EventEndPoints } from "@/constants/ApiConstants";
import { CreateEventPayload, UpdateEventPayload } from "@/types/event.types";
import { PaginationRequest } from "@/types/api.types";

const generic = (status: number, fallback: string): string => {
    switch (status) {
        case 0: return 'Network error. Please check your internet connection and try again.';
        case 400: return 'Invalid event data. Please check all required fields.';
        case 401: return 'Unauthorized. Please login again.';
        case 403: return 'Access denied. Only event owners can perform this action.';
        case 404: return 'Event not found.';
        case 429: return 'Too many requests. Please wait a moment.';
        case 500: return 'Server error. Please try again later.';
        default: return fallback;
    }
};

export const EventServicesError = {
    GetEventsError:   (s: number) => generic(s, 'Failed to load events. Please try again.'),
    CreateEventError: (s: number) => generic(s, 'Failed to create event. Please try again.'),
    UpdateEventError: (s: number) => generic(s, 'Failed to update event. Please try again.'),
    DeleteEventError: (s: number) => generic(s, 'Failed to delete event. Please try again.'),
};

export const EventServices = {
    // Public: Fetch all events (paged).
    GetEvents:         async (paginationRequest?: PaginationRequest) =>
        createApiCall(HttpMethod.GET, EventEndPoints.GetEvents(paginationRequest)),
    // Public: Fetch only upcoming events (upcoming=true filter). Used by event list and alert banner.
    GetUpcomingEvents: async (paginationRequest?: PaginationRequest) =>
        createApiCall(HttpMethod.GET, EventEndPoints.GetEvents(paginationRequest, true)),
    // Public: Fetch a single event by id.
    GetEventById:      async (id: string) => createApiCall(HttpMethod.GET, EventEndPoints.GetEventById(id)),
    // Authenticated: Create a new event. Creator becomes an owner.
    CreateEvent:       async (payload: CreateEventPayload) => createApiCall(HttpMethod.POST, EventEndPoints.PostEvent(), payload),
    // Owner: Update an existing event.
    UpdateEvent:       async (payload: UpdateEventPayload) => createApiCall(HttpMethod.PATCH, EventEndPoints.PatchEvent(payload.id), payload),
    // Owner: Delete an event.
    DeleteEvent:       async (id: string) => createApiCall(HttpMethod.DELETE, EventEndPoints.DeleteEvent(id)),
};
