import { EnvConfig } from "./EnvConfig";
import { PaginationRequest } from "../types/api.types";
import { getSelectedEventId } from "@/utils/eventContext";

export const AxiosConfig = {
	retry: 5,
	firstRetryAt: 200,
};

export const ApiBasePath = EnvConfig.ApiBasePath;

// Get EventId from localStorage instead of environment variable.
export const getEventId = (): string => getSelectedEventId() || "";

// Build a `?pageSize=...&continuationToken=...` query string. Returns empty string when omitted.
const pageQuery = (p?: PaginationRequest): string => {
	if (!p) return "";
	const parts = [`pageSize=${p.pageSize}`];
	if (p.continuationToken) parts.push(`continuationToken=${encodeURIComponent(p.continuationToken)}`);
	return `?${parts.join("&")}`;
};

