export const SearchEndPoints = {
	UnifiedSearch: (
		query: string,
		pageNumber?: number,
		pageSize?: number,
		schoolName?: string,
		entryYear?: number,
		lat?: number,
		lng?: number,
		radiusKm?: number,
	) => {
		const parts = [`searchText=${encodeURIComponent(query)}`];
		if (pageNumber !== undefined) parts.push(`pageNumber=${pageNumber}`);
		if (pageSize !== undefined) parts.push(`pageSize=${pageSize}`);
		if (schoolName) parts.push(`schoolName=${encodeURIComponent(schoolName)}`);
		if (entryYear !== undefined) parts.push(`entryYear=${entryYear}`);
		if (lat !== undefined) parts.push(`lat=${lat}`);
		if (lng !== undefined) parts.push(`lng=${lng}`);
		if (radiusKm !== undefined) parts.push(`radiusKm=${radiusKm}`);
		return `${ApiBasePath}/search?${parts.join("&")}`;
	},
	IndexProfiles: () => `${ApiBasePath}/search/profiles/index`,
	IndexBusinesses: () => `${ApiBasePath}/search/businesses/index`,
};
